use rocket::serde::json::Json;
use serde::Serialize;
use thiserror::Error;

/// Unified application error type for consistent API error responses.
#[derive(Debug, Error)]
pub enum AppError {
    #[error("Authentication required")]
    Unauthorized,

    #[error("Insufficient permissions")]
    Forbidden,

    #[error("Resource not found: {0}")]
    NotFound(String),

    #[error("Validation error: {0}")]
    Validation(String),

    #[error("Conflict: {0}")]
    Conflict(String),

    #[error("Account locked: {0}")]
    AccountLocked(String),

    #[error("Internal server error")]
    Internal(String),

    #[error("Database error: {0}")]
    Database(String),
}

#[derive(Serialize)]
pub struct ErrorResponse {
    pub error: String,
    pub message: String,
}

impl AppError {
    pub fn status(&self) -> Status {
        match self {
            AppError::Unauthorized => Status::Unauthorized,
            AppError::Forbidden => Status::Forbidden,
            AppError::NotFound(_) => Status::NotFound,
            AppError::Validation(_) => Status::UnprocessableEntity,
            AppError::Conflict(_) => Status::Conflict,
            AppError::AccountLocked(_) => Status::TooManyRequests,
            AppError::Internal(_) => Status::InternalServerError,
            AppError::Database(_) => Status::InternalServerError,
        }
    }

    pub fn to_response(&self) -> (Status, Json<ErrorResponse>) {
        let status = self.status();
        let response = ErrorResponse {
            error: format!("{:?}", std::mem::discriminant(self)),
            message: self.to_string(),
        };
        (status, Json(response))
    }
}
"}

