{"file_path": "/home/nahom/Desktop/Others/EaglePointAI/vibe-coding-projects/week-2/Scholarly/repo/backend/src/application/principal.rs", "content": "//! The authenticated principal — what the auth guard puts into request state
//! and what every authorization helper receives.
//!
//! A `Principal` is always the result of a verified bearer token on an
//! active session. Unauthenticated callers never get a `Principal`; they
//! get `AppError::Unauthorized` from the guard.

use serde::{Deserialize, Serialize};
use uuid::Uuid;

/// The five fixed roles in the RBAC model. Stored in the database under
/// `roles.name` as lowercase snake_case.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum Role {
    Admin,
    Librarian,
    DepartmentHead,
    Instructor,
    Viewer,
}

impl Role {
    pub fn as_db_name(self) -> &'static str {
        match self {
            Role::Admin => "admin",
            Role::Librarian => "librarian",
            Role::DepartmentHead => "department_head",
            Role::Instructor => "instructor",
            Role::Viewer => "viewer",
        }
    }

    pub fn from_db_name(name: &str) -> Option<Self> {
        match name {
            "admin" => Some(Role::Admin),
            "librarian" => Some(Role::Librarian),
