mod tests {
    use super::*;

    /// Build a tiny in-memory chain and verify that recomputing hashes
    /// matches and that tampering with any field breaks the check.
    #[test]
    fn compute_hash_is_deterministic() {
        let a = compute_hash(None, 1, Uuid::nil(), "auth.login.success", Some("null"));
        let b = compute_hash(None, 1, Uuid::nil(), "auth.login.success", Some("null"));
        assert_eq!(a, b);
    }

    #[test]
    fn hash_changes_when_any_input_changes() {
        let base = compute_hash(None, 1, Uuid::nil(), "x", Some("null"));
        assert_ne!(base, compute_hash(Some("prev"), 1, Uuid::nil(), "x", Some("null")));
        assert_ne!(base, compute_hash(None, 2, Uuid::nil(), "x", Some("null")));
        assert_ne!(
            base,
            compute_hash(None, 1, Uuid::new_v4(), "x", Some("null"))
        );
        assert_ne!(base, compute_hash(None, 1, Uuid::nil(), "y", Some("null")));
        assert_ne!(
            base,
            compute_hash(None, 1, Uuid::nil(), "x", Some("{\"a\":1}"))
        );
    }

    #[test]
    fn chained_hash_walk_matches_in_memory() {
        // Simulate a 3-entry chain in memory, then walk and verify.
        let id1 = Uuid::new_v4();
        let id2 = Uuid::new_v4();
        let id3 = Uuid::new_v4();
        let h1 = compute_hash(None, 1, id1, "a", Some("null"));
        let h2 = compute_hash(Some(&h1), 2, id2, "b", Some("null"));
        let h3 = compute_hash(Some(&h2), 3, id3, "c", Some("null"));

        // Tamper: flip action of entry 2 and recompute onward — h3 should differ.
        let h2_tampered = compute_hash(Some(&h1), 2, id2, "b_TAMPERED", Some("null"));
        let h3_following_tamper = compute_hash(Some(&h2_tampered), 3, id3, "c", Some("null"));
        assert_ne!(h3, h3_following_tamper);
    }
}
