    pub limit: u32,
}

impl Default for AuditSearch {
    fn default() -> Self {
        Self {
            actor_id: None,
            action: None,
            target_entity_type: None,
            target_entity_id: None,
            from: None,
            to: None,
            limit: default_limit(),
        }
    }
