//! failure they return a JSON body matching [`crate::errors::ErrorEnvelope`].

use rocket::serde::json::Json;
use rocket::{Request, State};
use serde::Serialize;
use sqlx::MySqlPool;

use crate::api::guards::{request_ip, request_user_agent, AuthedPrincipal};
use crate::application::auth_service::{self, LoginInput, LoginOutput, RequestContext};
