pub fn routes() -> Vec<rocket::Route> {
    routes![login, logout, me]
}

#[derive(Serialize)]
pub struct LoginBody {
    pub token: String,
    pub expires_at: chrono::NaiveDateTime,
    pub user: UserPublic,
}

#[derive(Serialize)]
pub struct UserPublic {
    pub id: uuid::Uuid,
    pub email: String,
    pub display_name: String,
    pub roles: Vec<String>,
    pub department_id: Option<uuid::Uuid>,
}

fn to_public(out: LoginOutput) -> LoginBody {
    LoginBody {
        token: out.token,
        expires_at: out.expires_at,
        user: UserPublic {
            id: out.principal.user_id,
            email: out.principal.email,
            display_name: out.principal.display_name,
            roles: out
                .principal
                .roles
                .iter()
                .map(|r| r.as_db_name().to_string())
                .collect(),
            department_id: out.principal.department_id,
        },
    }
}

/// POST /api/v1/auth/login
#[post("/login", data = "<body>")]
pub async fn login(
    body: Json<LoginInput>,
    pool: &State<MySqlPool>,
    config: &State<AppConfig>,
    req: &Request<'_>,
) -> AppResult<Json<LoginBody>> {
    let ctx_ip = request_ip(req);
    let ctx_ua = request_user_agent(req);
    let ctx = RequestContext {
        ip_address: ctx_ip.as_deref(),
        user_agent: ctx_ua.as_deref(),
    };

    let out = auth_service::login(pool.inner(), config.inner(), body.into_inner(), ctx).await?;
    Ok(Json(to_public(out)))
}

/// POST /api/v1/auth/logout
#[post("/logout")]
pub async fn logout(
    principal: AuthedPrincipal,
    pool: &State<MySqlPool>,
    req: &Request<'_>,
) -> AppResult<Json<serde_json::Value>> {
    let ctx_ip = request_ip(req);
    let ctx_ua = request_user_agent(req);
    let ctx = RequestContext {
        ip_address: ctx_ip.as_deref(),
        user_agent: ctx_ua.as_deref(),
    };
    auth_service::logout(pool.inner(), principal.as_ref(), ctx).await?;
    Ok(Json(serde_json::json!({ "ok": true })))
}

/// GET /api/v1/auth/me — return the current principal.
#[get("/me")]
pub async fn me(principal: AuthedPrincipal) -> AppResult<Json<UserPublic>> {
    let p = principal.into_inner();
    Ok(Json(UserPublic {
        id: p.user_id,
        email: p.email,
        display_name: p.display_name,
        roles: p.roles.iter().map(|r| r.as_db_name().to_string()).collect(),
        department_id: p.department_id,
    }))
}

