//!
//! Only `/me` is implemented in Phase 2. Full CRUD remains a Phase 3
//! responsibility. The remaining endpoints are scaffolded and guarded
//! with `AdminOnly` so nothing unprivileged can reach them.

use rocket::serde::json::Json;
use rocket::State;
use serde::Serialize;
use sqlx::MySqlPool;
use uuid::Uuid;

use crate::api::guards::{AdminOnly, AuthedPrincipal};
use crate::application::auth_service;
use crate::errors::{AppError, AppResult};

pub fn routes() -> Vec<rocket::Route> {
    routes![me, list_users, get_user, create_user_stub, update_user_stub, delete_user_stub]
}

#[derive(Serialize)]
pub struct UserProfile {
    pub id: Uuid,
    pub email: String,
    pub display_name: String,
    pub roles: Vec<String>,
    pub department_id: Option<Uuid>,
}

/// GET /api/v1/users/me
#[get("/me")]
pub async fn me(principal: AuthedPrincipal) -> AppResult<Json<UserProfile>> {
    let p = principal.into_inner();
    Ok(Json(UserProfile {
        id: p.user_id,
        email: p.email,
        display_name: p.display_name,
        roles: p.roles.iter().map(|r| r.as_db_name().to_string()).collect(),
        department_id: p.department_id,
    }))
}

/// GET /api/v1/users — list all users (Phase 2 returns the seeded set; full
/// filters/pagination come in Phase 3). Admin only.
#[get("/")]
pub async fn list_users(
    _admin: AdminOnly,
    pool: &State<MySqlPool>,
) -> AppResult<Json<Vec<UserProfile>>> {
    let rows = sqlx::query_as::<
        _,
        (String, String, String, Option<String>),
    >(
        r#"
        SELECT id, email, display_name, department_id
          FROM users
         ORDER BY email ASC
        "#,
    )
    .fetch_all(pool.inner())
    .await
    .map_err(|e| AppError::Database(format!("list_users: {}", e)))?;

    let mut out = Vec::with_capacity(rows.len());
    for (id_s, email, display_name, dept) in rows {
        let uid = Uuid::parse_str(&id_s).map_err(|e| AppError::Database(e.to_string()))?;
        let roles = auth_service::load_user_roles(pool.inner(), uid).await?;
        out.push(UserProfile {
            id: uid,
            email,
            display_name,
            roles: roles.iter().map(|r| r.as_db_name().to_string()).collect(),
            department_id: dept.as_deref().and_then(|s| Uuid::parse_str(s).ok()),
        });
    }
    Ok(Json(out))
}

/// GET /api/v1/users/<id> — admin only.
#[get("/<id>")]
pub async fn get_user(
    _admin: AdminOnly,
    pool: &State<MySqlPool>,
    id: &str,
) -> AppResult<Json<UserProfile>> {
    let uid = Uuid::parse_str(id)
        .map_err(|_| AppError::Validation("id must be a UUID".into()))?;
    let row = sqlx::query_as::<
        _,
        (String, String, String, Option<String>),
    >(
        r#"SELECT id, email, display_name, department_id FROM users WHERE id = ? LIMIT 1"#,
    )
    .bind(uid.to_string())
    .fetch_optional(pool.inner())
    .await
    .map_err(|e| AppError::Database(format!("get_user: {}", e)))?
    .ok_or_else(|| AppError::NotFound("user".into()))?;

    let roles = auth_service::load_user_roles(pool.inner(), uid).await?;
    Ok(Json(UserProfile {
        id: uid,
        email: row.1,
        display_name: row.2,
        roles: roles.iter().map(|r| r.as_db_name().to_string()).collect(),
        department_id: row.3.as_deref().and_then(|s| Uuid::parse_str(s).ok()),
    }))
}

// ── Mutating endpoints: admin-guarded stubs pending Phase 3 ──────────────

/// POST /api/v1/users — Phase 3 will implement. Returns 501-equivalent via
/// an explicit AppError so the envelope is consistent.
#[post("/")]
pub async fn create_user_stub(_admin: AdminOnly) -> AppResult<Json<serde_json::Value>> {
    Err(AppError::Validation(
        "user creation is scheduled for Phase 3".into(),
    ))
}

#[put("/<id>")]
pub async fn update_user_stub(
    _admin: AdminOnly,
    id: &str,
) -> AppResult<Json<serde_json::Value>> {
    let _ = Uuid::parse_str(id)
        .map_err(|_| AppError::Validation("id must be a UUID".into()))?;
    Err(AppError::Validation(
        "user update is scheduled for Phase 3".into(),
    ))
}

#[delete("/<id>")]
pub async fn delete_user_stub(
    _admin: AdminOnly,
    id: &str,
) -> AppResult<Json<serde_json::Value>> {
    let _ = Uuid::parse_str(id)
        .map_err(|_| AppError::Validation("id must be a UUID".into()))?;
    Err(AppError::Validation(
        "user deletion is scheduled for Phase 3".into(),
    ))
}
"}

