//!
//! Only `/me`, `/` (list) and `/<id>` (get) are implemented in Phase 2.
//! Mutating endpoints are admin-guarded but intentionally return a
//! validation error explaining they are scheduled for Phase 3 — this
//! keeps the route surface honest: callers cannot mistake a stub for a
//! real endpoint.

use rocket::serde::json::Json;
use rocket::State;
use serde::Serialize;
use sqlx::{MySqlPool, Row};
use uuid::Uuid;

use crate::api::guards::{AdminOnly, AuthedPrincipal};
use crate::application::auth_service;
use crate::errors::{AppError, AppResult};

pub fn routes() -> Vec<rocket::Route> {
    routes![
        me,
        list_users,
        get_user,
        create_user_stub,
        update_user_stub,
        delete_user_stub
    ]
}

#[derive(Serialize)]
pub struct UserProfile {
    pub id: Uuid,
    pub email: String,
    pub display_name: String,
    pub roles: Vec<String>,
    pub department_id: Option<Uuid>,
}

/// GET /api/v1/users/me
#[get("/me")]
pub async fn me(principal: AuthedPrincipal) -> AppResult<Json<UserProfile>> {
    let p = principal.into_inner();
    Ok(Json(UserProfile {
        id: p.user_id,
        email: p.email,
        display_name: p.display_name,
        roles: p.roles.iter().map(|r| r.as_db_name().to_string()).collect(),
        department_id: p.department_id,
    }))
}

/// GET /api/v1/users — admin only.
#[get("/")]
pub async fn list_users(
    _admin: AdminOnly,
    pool: &State<MySqlPool>,
) -> AppResult<Json<Vec<UserProfile>>> {
    let rows = sqlx::query(
        r#"SELECT id, email, display_name, department_id
             FROM users
            ORDER BY email ASC"#,
    )
    .fetch_all(pool.inner())
    .await
    .map_err(|e| AppError::Database(format!("list_users: {}", e)))?;

    let mut out = Vec::with_capacity(rows.len());
    for row in rows {
        let id_s: String = row.try_get("id").map_err(|e| AppError::Database(e.to_string()))?;
        let email: String = row
            .try_get("email")
            .map_err(|e| AppError::Database(e.to_string()))?;
        let display_name: String = row
            .try_get("display_name")
            .map_err(|e| AppError::Database(e.to_string()))?;
        let dept: Option<String> = row
            .try_get("department_id")
            .map_err(|e| AppError::Database(e.to_string()))?;
        let uid = Uuid::parse_str(&id_s).map_err(|e| AppError::Database(e.to_string()))?;
        let roles = auth_service::load_user_roles(pool.inner(), uid).await?;
        out.push(UserProfile {
            id: uid,
            email,
            display_name,
            roles: roles.iter().map(|r| r.as_db_name().to_string()).collect(),
            department_id: dept.as_deref().and_then(|s| Uuid::parse_str(s).ok()),
        });
    }
    Ok(Json(out))
}

/// GET /api/v1/users/<id> — admin only.
#[get("/<id>")]
pub async fn get_user(
    _admin: AdminOnly,
    pool: &State<MySqlPool>,
    id: &str,
) -> AppResult<Json<UserProfile>> {
    let uid =
        Uuid::parse_str(id).map_err(|_| AppError::Validation("id must be a UUID".into()))?;
    let row = sqlx::query(
        r#"SELECT id, email, display_name, department_id
             FROM users
            WHERE id = ?
            LIMIT 1"#,
    )
    .bind(uid.to_string())
    .fetch_optional(pool.inner())
    .await
    .map_err(|e| AppError::Database(format!("get_user: {}", e)))?
    .ok_or_else(|| AppError::NotFound("user".into()))?;

    let email: String = row
        .try_get("email")
        .map_err(|e| AppError::Database(e.to_string()))?;
    let display_name: String = row
        .try_get("display_name")
        .map_err(|e| AppError::Database(e.to_string()))?;
    let dept: Option<String> = row
        .try_get("department_id")
        .map_err(|e| AppError::Database(e.to_string()))?;

    let roles = auth_service::load_user_roles(pool.inner(), uid).await?;
    Ok(Json(UserProfile {
        id: uid,
        email,
        display_name,
        roles: roles.iter().map(|r| r.as_db_name().to_string()).collect(),
        department_id: dept.as_deref().and_then(|s| Uuid::parse_str(s).ok()),
    }))
}

