12	pub enum Role {
13	    Admin,
14	    Librarian,
15	    DepartmentHead,
16	    Instructor,
17	    Viewer,
18	}
19	
20	impl Role {
21	    /// Returns a numeric privilege level for comparison.
22	    ///
23	    /// Higher values indicate greater privilege.
24	    pub fn level(&self) -> u8 {
25	        match self {
26	            Role::Admin => 100,
27	            Role::Librarian => 80,
28	            Role::DepartmentHead => 60,
29	            Role::Instructor => 40,
30	            Role::Viewer => 20,
31	        }
32	    }
33	}
34	
35	impl Default for Role {
36	    fn default() -> Self {
37	        Role::Viewer
38	    }
39	}
