41	impl std::fmt::Display for Role {
42	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
43	        let label = match self {
44	            Role::Admin => "Admin",
45	            Role::Librarian => "Librarian",
46	            Role::DepartmentHead => "Department Head",
47	            Role::Instructor => "Instructor",
