        q = q.bind(d.to_string());
    }

    let rows = q
        .fetch_all(pool)
        .await
        .map_err(|e| AppError::Database(format!("foot_traffic: {}", e)))?;

    let mut out = Vec::with_capacity(rows.len());
    for row in rows {
        let day: chrono::NaiveDate = row
            .try_get("day")
            .map_err(|e| AppError::Database(e.to_string()))?;
        let count: i64 = row
            .try_get("count")
            .map_err(|e| AppError::Database(e.to_string()))?;
        out.push(DashboardRow {
